final:
module RefModule(
   input                clk,
   input                rst_n,
   input                en,
   input                dir,

   output reg [4-1:1-1]     count
);
    always @(posedge clk or negedge rst_n) begin
        if (!rst_n) count <= 4'd0;
        else if (en) begin
            if (dir) count <= count + 1;
            else count <= count - 1;
        end
    end
endmodule
